tasks.details:
Build a responsive web application that serves as the Mini App frontend with the following screens:

1. Model & Generation:
   - Model selection dropdown (gpt-4o, gpt-4.1-turbo, sonnet-3.7, etc.)
   - Temperature slider (0.0-1.0)

2. Memory:
   - List of recent memories with search functionality
   - Clear button with confirmation dialog

3. Notifications:
   - Toggle switches for service_messages and cost_summaries

4. About persona:
   - Description of the current persona
   - Last mood snapshot visualization

Use Telegram's WebApp API for authentication and integration. The app should be responsive and work well on mobile devices.

Example implementation structure:
```javascript
// index.js - Entry point
import React from 'react';
import ReactDOM from 'react-dom';
import App from './App';

ReactDOM.render(<App />, document.getElementById('root'));

// App.js - Main component
import React, { useState, useEffect } from 'react';
import { BrowserRouter, Routes, Route } from 'react-router-dom';
import Navbar from './components/Navbar';
import ModelSettings from './screens/ModelSettings';
import MemoryView from './screens/MemoryView';
import NotificationSettings from './screens/NotificationSettings';
import AboutPersona from './screens/AboutPersona';
import { verifyTelegramWebAppData } from './utils/auth';
import { fetchSettings, updateSettings } from './api/settings';

function App() {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [userData, setUserData] = useState(null);
  const [settings, setSettings] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    // Initialize Telegram WebApp
    const tg = window.Telegram.WebApp;
    tg.expand();

    // Verify authentication
    if (tg.initData) {
      const authResult = verifyTelegramWebAppData(tg.initData);
      if (authResult.verified) {
        setIsAuthenticated(true);
        setUserData(authResult.user);

        // Fetch user settings
        const urlParams = new URLSearchParams(window.location.search);
        const persona = urlParams.get('persona') || 'eve';

        fetchSettings(persona, authResult.user.id)
          .then(data => {
            setSettings(data);
            setLoading(false);
          })
          .catch(err => {
            console.error('Error fetching settings:', err);
            setLoading(false);
          });
      } else {
        setLoading(false);
      }
    } else {
      setLoading(false);
    }
  }, []);

  const handleSettingsUpdate = (updates) => {
    if (!isAuthenticated || !userData) return;

    updateSettings(userData.id, updates)
      .then(updatedSettings => {
        setSettings(updatedSettings);
        // Notify the Telegram app that data has changed
        window.Telegram.WebApp.MainButton.setText('Settings Saved');
        window.Telegram.WebApp.MainButton.show();
        setTimeout(() => {
          window.Telegram.WebApp.MainButton.hide();
        }, 2000);
      })
      .catch(err => {
        console.error('Error updating settings:', err);
      });
  };

  if (loading) {
    return <div className="loading">Loading...</div>;
  }

  if (!isAuthenticated) {
    return <div className="error">Authentication failed. Please open this app from Telegram.</div>;
  }

  return (
    <BrowserRouter>
      <div className="app">
        <Navbar />
        <div className="content">
          <Routes>
            <Route path="/" element={<ModelSettings settings={settings} onUpdate={handleSettingsUpdate} />} />
            <Route path="/memory" element={<MemoryView userData={userData} />} />
            <Route path="/notifications" element={<NotificationSettings settings={settings} onUpdate={handleSettingsUpdate} />} />
            <Route path="/about" element={<AboutPersona userData={userData} />} />
          </Routes>
        </div>
      </div>
    </BrowserRouter>
  );
}

export default App;
```

Implement the necessary components and screens as outlined above.

Implement authentication for the Mini App:

1. Client-side validation of Telegram WebApp data
2. Server-side verification of auth hash
3. Middleware for protecting API endpoints

Example implementation for client-side:
```javascript
// utils/auth.js
export function verifyTelegramWebAppData(initData) {
  if (!initData) {
    return { verified: false, error: 'No init data provided' };
  }

  try {
    // Parse the initData
    const params = new URLSearchParams(initData);
    const user = JSON.parse(params.get('user') || '{}');

    // In a real implementation, we would verify the hash on the server side
    // For now, we'll just check if user data exists
    if (!user.id) {
      return { verified: false, error: 'Invalid user data' };
    }

    return { verified: true, user };
  } catch (error) {
    console.error('Error parsing WebApp data:', error);
    return { verified: false, error: error.message };
  }
}
```

Example implementation for server-side:
```python
# Server-side verification in middleware/auth.py
import hmac
import hashlib
from urllib.parse import parse_qsl
import json

class TelegramAuthMiddleware:
    def __init__(self, bot_token):
        self.bot_token = bot_token
        # Create a secret key by hashing the bot token with SHA256
        self.secret_key = hashlib.sha256(bot_token.encode()).digest()

    def verify_telegram_data(self, init_data):
        # Parse the data
        data_dict = dict(parse_qsl(init_data))

        if "hash" not in data_dict:
            return None

        # Get the hash from the data
        received_hash = data_dict.pop("hash")

        # Sort the data alphabetically
        data_check_string = "\n".join(f"{k}={v}" for k, v in sorted(data_dict.items()))

        # Calculate the HMAC-SHA-256 signature
        calculated_hash = hmac.new(
            self.secret_key,
            data_check_string.encode(),
            hashlib.sha256
        ).hexdigest()

        # Compare the received hash with the calculated one
        if calculated_hash != received_hash:
            return None

        # Extract user data
        try:
            user_data = json.loads(data_dict.get("user", "{}"))
            return user_data
        except:
            return None
